import { useState, useRef, useEffect } from 'react';
import { CalendarDays, ChevronDown } from 'lucide-react';
import { useDateRange } from '@hooks/useDateRange';
import { DATE_PRESETS } from '@utils/constants';
import { formatDate } from '@utils/formatters';
import { Calendar } from '@components/Calendar/Calendar';
import './DateRangePicker.scss';

export function DateRangePicker() {
  const { dateRange, setPreset, setDateRange } = useDateRange();
  const [open, setOpen]       = useState(false);
  const [openCal, setOpenCal] = useState(null); // 'start' | 'end' | null
  const ref = useRef(null);

  useEffect(() => {
    function handler(e) {
      if (ref.current && !ref.current.contains(e.target)) {
        setOpen(false);
        setOpenCal(null);
      }
    }
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const label = `${formatDate(dateRange.startDate)} – ${formatDate(dateRange.endDate)}`;

  return (
    <div className={`drp ${open ? 'drp--open' : ''}`} ref={ref}>
      {/* Pill trigger */}
      <button
        type="button"
        className="drp__trigger"
        onClick={() => { setOpen(v => !v); setOpenCal(null); }}
        aria-expanded={open}
        aria-haspopup="true"
      >
        <CalendarDays size={15} strokeWidth={1.75} className="drp__cal-icon" />
        <span className="drp__label">{label}</span>
        <ChevronDown size={14} strokeWidth={2} className="drp__chevron" />
      </button>

      {/* Dropdown panel */}
      {open && (
        <div className="drp__panel" role="dialog" aria-label="Select date range">
          {/* Quick presets */}
          <ul className="drp__presets">
            {DATE_PRESETS.map(p => (
              <li key={p.value}>
                <button
                  type="button"
                  className="drp__preset-btn"
                  onClick={() => { setPreset(p.value); setOpen(false); setOpenCal(null); }}
                >
                  {p.label}
                </button>
              </li>
            ))}
          </ul>

          {/* Custom range */}
          <div className="drp__custom">
            <div className="drp__field">
              <span className="drp__field-label">From</span>
              <button
                type="button"
                className={`drp__date-btn${openCal === 'start' ? ' drp__date-btn--active' : ''}`}
                onClick={() => setOpenCal(openCal === 'start' ? null : 'start')}
              >
                <CalendarDays size={12} strokeWidth={1.75} />
                {formatDate(dateRange.startDate)}
              </button>
            </div>

            <span className="drp__sep">→</span>

            <div className="drp__field">
              <span className="drp__field-label">To</span>
              <button
                type="button"
                className={`drp__date-btn${openCal === 'end' ? ' drp__date-btn--active' : ''}`}
                onClick={() => setOpenCal(openCal === 'end' ? null : 'end')}
              >
                <CalendarDays size={12} strokeWidth={1.75} />
                {formatDate(dateRange.endDate)}
              </button>
            </div>
          </div>

          {/* Inline custom calendar */}
          {openCal && (
            <div className="drp__cal-wrap">
              <Calendar
                key={openCal}
                value={openCal === 'start' ? dateRange.startDate : dateRange.endDate}
                minDate={openCal === 'end'   ? dateRange.startDate : undefined}
                maxDate={openCal === 'start' ? dateRange.endDate   : undefined}
                onChange={val => {
                  if (openCal === 'start') setDateRange(val, dateRange.endDate);
                  else                     setDateRange(dateRange.startDate, val);
                  setOpenCal(null);
                }}
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
}
