import { useState } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import './Calendar.scss';

const DAYS   = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];
const MONTHS = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December',
];

function toDate(str) {
  if (!str) return null;
  const [y, m, d] = str.split('-').map(Number);
  return new Date(y, m - 1, d);
}

function toStr(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

export function Calendar({ value, onChange, minDate, maxDate }) {
  const selected = toDate(value);
  const today = new Date(); today.setHours(0, 0, 0, 0);

  const [cursor, setCursor] = useState(() => {
    const base = selected || today;
    return new Date(base.getFullYear(), base.getMonth(), 1);
  });

  const year  = cursor.getFullYear();
  const month = cursor.getMonth();
  const min   = toDate(minDate);
  const max   = toDate(maxDate);

  const firstWeekday = new Date(year, month, 1).getDay();
  const daysInMonth  = new Date(year, month + 1, 0).getDate();
  const daysInPrev   = new Date(year, month, 0).getDate();

  const cells = [];
  for (let i = firstWeekday - 1; i >= 0; i--) cells.push({ day: daysInPrev - i, current: false });
  for (let d = 1; d <= daysInMonth; d++)       cells.push({ day: d, current: true });
  while (cells.length % 7 !== 0)               cells.push({ day: cells.length - daysInMonth - firstWeekday + 1, current: false });

  function isDisabled(cell) {
    if (!cell.current) return true;
    const d = new Date(year, month, cell.day);
    if (min && d < min) return true;
    if (max && d > max) return true;
    return false;
  }

  function isSelected(cell) {
    return cell.current && selected &&
      cell.day === selected.getDate() &&
      month === selected.getMonth() &&
      year  === selected.getFullYear();
  }

  function isToday(cell) {
    return cell.current &&
      cell.day === today.getDate() &&
      month === today.getMonth() &&
      year  === today.getFullYear();
  }

  return (
    <div className="cal">
      <div className="cal__header">
        <button
          type="button"
          className="cal__nav"
          onClick={() => setCursor(new Date(year, month - 1, 1))}
          aria-label="Previous month"
        >
          <ChevronLeft size={14} strokeWidth={2} />
        </button>
        <span className="cal__title">{MONTHS[month]} {year}</span>
        <button
          type="button"
          className="cal__nav"
          onClick={() => setCursor(new Date(year, month + 1, 1))}
          aria-label="Next month"
        >
          <ChevronRight size={14} strokeWidth={2} />
        </button>
      </div>

      <div className="cal__grid">
        {DAYS.map(d => <span key={d} className="cal__weekday">{d}</span>)}
        {cells.map((cell, i) => (
          <button
            key={i}
            type="button"
            disabled={isDisabled(cell)}
            tabIndex={cell.current && !isDisabled(cell) ? 0 : -1}
            className={[
              'cal__day',
              !cell.current    && 'cal__day--other',
              isSelected(cell) && 'cal__day--selected',
              isToday(cell)    && 'cal__day--today',
            ].filter(Boolean).join(' ')}
            onClick={() => !isDisabled(cell) && onChange(toStr(new Date(year, month, cell.day)))}
          >
            {cell.day}
          </button>
        ))}
      </div>

      <div className="cal__footer">
        <button type="button" className="cal__footer-btn" onClick={() => onChange('')}>
          Clear
        </button>
        <button
          type="button"
          className="cal__footer-btn"
          onClick={() => {
            onChange(toStr(today));
            setCursor(new Date(today.getFullYear(), today.getMonth(), 1));
          }}
        >
          Today
        </button>
      </div>
    </div>
  );
}
